mapper.select:
SELECT COUNT(1)
FROM c_owner_property
WHERE uid = #{uid} 
  AND tenant_id = #{tenantId} 
  AND account_status != 1

SELECT DISTINCT building_id
FROM c_owner_property
WHERE uid = #{uid} AND tenant_id = #{tenantId}

SELECT cu.uid AS uid, cu.account_id AS account_id, a.phone AS phone, a.real_name AS real_name_cipher, a.real_name_verified AS real_name_verified, cu.auth_level AS auth_level, a.status AS account_status, COUNT(op.opid) AS property_count, COALESCE(SUM(op.build_area), 0) AS total_build_area, cu.create_time AS create_time FROM t_account a JOIN c_user cu ON cu.account_id = a.account_id JOIN c_owner_property op ON op.uid = cu.uid
AND op.tenant_id = #{q.tenantId}
GROUP BY cu.uid, cu.account_id, a.phone, a.real_name, a.real_name_verified, cu.auth_level, a.status, cu.create_time ORDER BY cu.uid DESC LIMIT #{q.size} OFFSET (#{q.page} - 1) * #{q.size}

SELECT cu.uid AS uid, cu.account_id AS account_id, a.phone AS phone, a.real_name AS real_name_cipher, a.real_name_verified AS real_name_verified, cu.auth_level AS auth_level, a.status AS account_status, COUNT(op.opid) AS property_count, COALESCE(SUM(op.build_area), 0) AS total_build_area, cu.create_time AS create_time FROM t_account a JOIN c_user cu ON cu.account_id = a.account_id JOIN c_owner_property op ON op.uid = cu.uid WHERE cu.uid = #{uid}
AND op.tenant_id = #{tenantId}
GROUP BY cu.uid, cu.account_id, a.phone, a.real_name, a.real_name_verified, cu.auth_level, a.status, cu.create_time

SELECT op.opid AS opid, op.tenant_id AS tenant_id, COALESCE(pr.community_name, tc.tenant_name, '小区 ' || op.tenant_id::TEXT) AS community_name, op.building_id AS building_id, COALESCE(pr.building_name, op.building_id::TEXT || ' 号楼') AS building_name, COALESCE(pr.unit_name, '默认单元') AS unit_name, op.room_id AS room_id, COALESCE(pr.room_name, op.room_id::TEXT || ' 室') AS room_name, op.build_area AS build_area, op.is_joint_ownership AS is_joint_ownership, op.is_voting_delegate AS is_voting_delegate, op.account_status AS account_status, op.verify_type AS verify_type, op.verify_status AS verify_status FROM c_owner_property op LEFT JOIN c_property_roster pr ON pr.tenant_id = op.tenant_id AND pr.room_id = op.room_id AND pr.status = 'ACTIVE' LEFT JOIN t_tenant_community tc ON tc.tenant_id = op.tenant_id WHERE op.uid = #{uid}
AND op.tenant_id = #{tenantId}
AND op.account_status = 1 ORDER BY op.building_id, op.room_id
